团队里有同学说他做了个'插件化'的工具扩展系统，但我看了下感觉哪里怪怪的，每次加新工具还是要改 5、6 个地方。下面是核心代码，帮我看看这是不是真正的插件化，有没有反模式，要怎么改？

```ts
// extensions/index.ts
import { MotionExt } from './motion'
import { RelightExt } from './relight'
import { ShotsExt } from './shots'

export const extensions = {
  motion: { component: MotionExt, priority: 1 },
  relight: { component: RelightExt },
  shots: { component: ShotsExt, priority: 3, customLayout: true },
}

export function shouldShowExtension(key: string, user: User) {
  if (key === 'motion') {
    if (user.plan === 'free' && user.creditsLeft < 10) return false
    return true
  }
  if (key === 'shots') {
    const motionState = useStore((s) => s.motionOpen)
    return !motionState && user.plan !== 'free'
  }
  return true
}

export function getExtensionByKey(key: string) {
  const ext = extensions[key]
  if (key === 'shots' && ext.customLayout) {
    return { ...ext, layout: SpecialShotsLayout }
  }
  return ext
}
